 7→/**
 8→ * Use this function to start a new coroutine in [CoroutineStart.UNDISPATCHED] mode &mdash;
 9→ * immediately execute the coroutine in the current thread until the next suspension.
10→ * It does not use [ContinuationInterceptor], but updates the context of the current thread for the new coroutine.
11→ */
12→internal fun <R, T> (suspend (R) -> T).startCoroutineUndispatched(receiver: R, completion: Continuation<T>) {
13→    val actualCompletion = probeCoroutineCreated(completion)
14→    val value = try {
15→        /* The code below is started immediately in the current stack-frame
16→         * and runs until the first suspension point. */
17→        withCoroutineContext(actualCompletion.context, null) {
18→            probeCoroutineResumed(actualCompletion)
19→            startCoroutineUninterceptedOrReturn(receiver, actualCompletion)
20→        }
21→    } catch (e: Throwable) {
22→        val reportException = if (e is DispatchException) e.cause else e
23→        actualCompletion.resumeWithException(reportException)
24→        return
25→    }
26→    if (value !== COROUTINE_SUSPENDED) {
27→        @Suppress("UNCHECKED_CAST")
28→        actualCompletion.resume(value as T)
29→    }
30→}
31→
32→/**
33→ * Starts this coroutine with the given code [block] in the same context and returns the coroutine result when it
34→ * completes without suspension.
35→ * This function shall be invoked at most once on this coroutine.
36→ * This function checks cancellation of the outer [Job] on fast-path.
37→ *
38→ * It starts the coroutine using [startCoroutineUninterceptedOrReturn].
39→ */
40→internal fun <T, R> ScopeCoroutine<T>.startUndispatchedOrReturn(receiver: R, block: suspend R.() -> T): Any? {
41→    return undispatchedResult({ true }) {
42→        block.startCoroutineUninterceptedOrReturn(receiver, this)
43→    }
44→}
45→
46→/**
47→ * Same as [startUndispatchedOrReturn], but ignores [TimeoutCancellationException] on fast-path.
48→ */
49→internal fun <T, R> ScopeCoroutine<T>.startUndispatchedOrReturnIgnoreTimeout(
50→    receiver: R, block: suspend R.() -> T
51→): Any? {
52→    return undispatchedResult({ e -> !(e is TimeoutCancellationException && e.coroutine === this) }) {
53→        block.startCoroutineUninterceptedOrReturn(receiver, this)
54→    }
55→}
56→
57→private inline fun <T> ScopeCoroutine<T>.undispatchedResult(
58→    shouldThrow: (Throwable) -> Boolean,
59→    startBlock: () -> Any?

